def add(a: int, b: int) -> int:
    return a + b

def multiply(a: int, b: int) -> int:
    return a * b

class Calculator:
    result: int

    def __init__(self, initial: int = 0):
        self.result = initial

    def add_to(self, value: int) -> int:
        self.result = self.result + value
        return self.result

    def get_result(self) -> int:
        return self.result

    def reset(self) -> None:
        self.result = 0
